async function resolveValidationTargets(sourcePath) {
  const stats = await statPath(sourcePath);
  if (!stats.ok) {
    return stats;
  }
  if (stats.value.isFile()) {
    return {
      ok: true,
      value: [
        {
          collectionFilePath: sourcePath,
          workspaceRoot: inferWorkspaceRootForCollectionFile(sourcePath)
        }
      ]
    };
  }
  if (!stats.value.isDirectory()) {
    return {
      error: {
        code: "path.unsafe" /* PathUnsafe */,
        context: { displayPath: sourcePath },
        message: "Expected a collection file or source workspace directory."
      },
      ok: false
    };
  }
  const discovered = await discoverCollectionFiles({
    workspaceRoot: sourcePath
  });
  if (!discovered.ok) {
    return discovered;
  }
  return {
    ok: true,
    value: discovered.value.map((file2) => ({
      collectionFilePath: file2.path.absolutePath.value,
      workspaceRoot: sourcePath
    }))
  };
}
async function validateCollectionForBuild(collection, workspaceRoot) {
  const renderable = toRenderableCollection(collection);
  if (!renderable.ok) {
    return renderable;
  }
  const assets = await validateSourceAssets({
    collection,
    workspaceRoot
  });
  if (!assets.ok) {
    return assets;
  }
  return renderable;
}
async function statPath(sourcePath) {
  try {
    return {
      ok: true,
      value: await fs3.stat(sourcePath)
    };
  } catch {
    return {
      error: {
        code: "filesystem.readFailed" /* FilesystemReadFailed */,
        context: { displayPath: sourcePath },
        message: "Failed to read source path."
      },
      ok: false
    };
  }
}
function inferWorkspaceRootForCollectionFile(collectionFilePath) {
  const collectionDirectory = path5.dirname(collectionFilePath);
  if (path5.basename(collectionDirectory) === "collections") {
    return path5.dirname(collectionDirectory);
  }
  return collectionDirectory;
}
function printError(output, error48) {
  const serialized = serializeGridgenError(error48);
  const context = Object.entries(serialized.context).map(([key, value]) => `${key}=${String(value)}`).join(" ");
  output.error(context.length === 0 ? `${serialized.code}: ${serialized.message}` : `${serialized.code}: ${serialized.message} (${context})`);
}
function parsePortOption(input) {
  const port = Number(input);
  if (!Number.isInteger(port)) {
    throw new CommanderError(1, "commander.invalidArgument", "Port must be an integer.");
  }
  return port;
}
function parseLayoutOption(input) {
  if (input === "classic" || input === "poster") {
    return input;
  }
  throw new CommanderError(1, "commander.invalidArgument", "Layout must be either classic or poster.");
}
function parseBuildTargetOption(input) {
  if (input === "astro-react" || input === "jekyll") {
    return input;
  }
  throw new CommanderError(1, "commander.invalidArgument", "Target must be either astro-react or jekyll.");
}
async function openAuthoringUrl(url2, openUrl) {
  try {
    if (openUrl !== undefined) {
      await openUrl(url2);
      return { ok: true };
    }
    Bun.spawn(["open", url2], {
      stderr: "ignore",
      stdout: "ignore"
    });
    return { ok: true };
  } catch {
    return {
      error: {
        code: "server.startupFailed" /* ServerStartupFailed */,
        context: { fieldPath: "open" },
        message: "Failed to open the authoring URL."
      },
      ok: false
    };
  }
}

